const fX = bX + pad, fY = bY + pad;
const fWmax = bW - pad * 2, fH = bH - pad * 2;
const fR = bR - pad + 2;
const fillW = fWmax * (p / 100);
const fRr = p >= 99 ? fR : 5;

const tX = bX + bW / 2;
const tY = bY + bH / 2;

return {
  backgroundColor: "transparent",
  animation: true,
  animationDuration: 900,
